INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-f0899a01-moex-00017', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列關於被告之傳喚與拘提的敘述，請依據法律規定與實務見解，判斷何者正確？', '["為保障人權，被告經合法傳喚，無正當理由不到場者，應再次合法傳喚，不得逕予拘提", "被告犯罪嫌疑重大，且為外國人（無我國國籍）者，必要時，得不經傳喚逕行拘提", "對於到場之被告，經面告以下次應到之日、時、處所及如不到場得命拘提，並記明筆錄者，無 須再另行送達傳票", "司法警察偵查犯罪，有事實足認為特定人犯罪嫌疑重大而情況急迫者，得逕行拘提之，但應即 報請檢察官簽發拘票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00018', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '刑事訴訟法中關於訊問被告方法之規定，下列敘述何者正確？', '["司法警察詢問犯罪嫌疑人，原則上不得於夜間行之，但犯罪嫌疑人請求立即詢問者，應即時為之", "司法警察詢問被告時，應先告知被告得選任辯護人。若無法負擔辯護人費用，國家將為其聘請", "訊問被告時，若被告有數人，訊問者為發見真實，應命被告相互對質", "訊問被告應全程錄音錄影，若筆錄內所載被告之陳述與錄音錄影內容不符，應重新繕打筆錄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00019', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列關於執行扣押方法的敘述，何者正確？', '["非附隨於搜索之扣押，除以得為證據之物而扣押者外，均應經法官裁定", "司法警察於偵查中有相當理由認為情況急迫，有立即扣押之必要時，得逕行扣押", "司法警察實施扣押時，若發見另案應扣押之物，不得即予扣押，應另行聲請該管法院許可扣押", "日間開始搜索或扣押者，若至夜間尚未完成，即應停止執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00020', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列關於司法警察的偵查職能，何者錯誤？', '["司法警察應受檢察官及司法警察官之命令，偵查犯罪", "檢察官對於司法警察移送或報告之案件，認為調查未完備者，得發交其他司法警察調查", "基於檢察官的偵查主體地位，司法警察知有犯罪嫌疑者，應先報請檢察官指揮偵辦，始得依法 進行調查", "司法警察訊問犯罪嫌疑人時，若有事實認為辯護人行為不當足以影響偵查秩序，司法警察得禁 止辯護人在場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00021', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '我國刑事訴訟法中關於起訴的規定，下列何者錯誤？', '["檢察官發見有應不起訴或以不起訴為適當之情形者，得以言詞或書面撤回起訴，但應於第一審 辯論終結前為之", "於第一審辯論終結前，得就本罪之誣告罪追加起訴", "起訴之效力，僅及於檢察官所指之被告", "檢察官雖然僅就犯罪事實之一部起訴，但其效力仍及於全部"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00022', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '檢察官甲懷疑X和某起貪污案件有關，於是以傳票要求被告X到案說明，X主動到案，甲訊問後 認為X嫌疑重大且有逃亡之虞，非予羈押顯難進行追訴，請問甲後續應該採用何種處置最為適當？', '["由於甲已經訊問完X，故可直接依照刑事訴訟法第93條第2項向法院聲請羈押", "甲應該先依照刑事訴訟法第76條之規定拘提X並再次訊問後，再向法院聲請羈押", "甲應該先依照刑事訴訟法第228條第4項之規定逮捕X，並將逮捕所依照之事實告知X後聲請 法院羈押之", "甲應該放走X，不得直接聲請羈押"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00023', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '依照刑事訴訟法與實務見解，下列那一個狀況的法官不需自行迴避？', '["甲法官所住的大樓因遭小偷竊盜，甲亦受有損失，於是主動向警方提出告訴，經起訴後案件被 分到由甲審理", "乙法官接受告訴人所提出的准許提起自訴聲請並裁定允許提出自訴，但經X提出自訴後案件被 分到由乙審理", "丙法官判決被告X有罪確定後，X又提起再審的聲請，案件被分到由丙審理", "最高法院法官丁撤銷了被告Y的有罪判決並發回高等法院更審，但經數次撤銷發回後，依照內 部要點，於更三審開始又被分到由丁審理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00024', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '警察甲於KTV臨檢時發現被告X腳下有大量毒品，懷疑X有吸毒，於是在以現行犯逮捕X後， 意圖對其進行強制採尿，請問依照憲法判決等實務見解，下列何者正確？', '["甲可以直接以導尿管等侵入性方式強制導尿", "警察可以自行進行強制採尿不須先行得到檢察官同意", "受採尿者得於受採取尿液後10日內，聲請該管法院撤銷採尿許可", "警察在採尿後2天內，也必須陳報該管檢察官許可"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00025', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '下列關於刑事訴訟法中的送達規定，何者規定錯誤？', '["送達文書於在監獄或看守所之人，應囑託該監所長官為之", "被告之住、居所、事務所及所在地不明者，得為公示送達", "法院文書之送達，應由司法警察行之，不能由郵務機構行之", "公示送達自最後登載報紙或通知公告之日起，需經30日始發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00026', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-114-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '關於刑事訴訟中證據的概念，綜合法律規定與實務見解，下列何者錯誤？', '["無證據能力之證據，必定無證明力，不得作為判斷之依據", "被告於審判外之言詞或書面陳述，除法律另有規定者外，不得作為證據", "被告若陳述其自白係在疲勞訊問下作成時，應先於其他事證而為調查", "事實於法院已顯著者，當事人無須進行舉證"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:30+00:00", "source_pdf_sha1": "910528340b75", "answer_pdf_sha1": "19e18625774d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "608", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
